db:insert.db:input-parameters:
#[{
  flujo: vars.nombreFlujo default "flujo-desconocido",
  operacion: vars.operacion default "operacion-desconocida",
  mensaje_error: vars.mensajeError default "Error no controlado",
  detalle_error: vars.detalleError default "Sin detalle"
}]

ee:message.ee:set-payload:
%dw 2.0
output application/java
ns soap http://schemas.xmlsoap.org/soap/envelope/
---
{
    body: {
        soap#Fault: {
            faultcode: "soap:Server",
            faultstring: vars.mensajeError default "Error no controlado",
            detail: {
                codigo: vars.codigoError default "APP:UNKNOWN",
                descripcion: vars.detalleError default "Sin detalle"
            }
        }
    } write "application/xml"
}

%dw 2.0
output application/json
---
{
	error: vars.errorInfo.respuestaUsuario default "El proceso se ha tenido que cancelar por errores durante la ejecución"
}

db:update.db:input-parameters:
#[{
  office_id: vars.estadoHvacActualizado.office_id,
  hvac_mode: vars.estadoHvacActualizado.hvac_mode,
  hvac_target: vars.estadoHvacActualizado.hvac_target,
  ciclos_estables: vars.estadoHvacActualizado.ciclos_estables
}]

